args.sparql:
SELECT (COUNT(?race) AS ?numRaces)
WHERE {
  ?season wdt:P31 wd:Q1556920;
          wdt:P4455 wd:Q9673;
          wdt:P580 ?startDate.
  FILTER(STRSTARTS(STR(?startDate), "2015"))
  ?race wdt:P2550 ?season;
        wdt:P31 wd:Q3064.
}
GROUP BY ?season
ORDER BY DESC(?numRaces)
LIMIT 1 OFFSET 1
